/**
 * Bogo Sort implementation.
 * Repeatedly shuffles the array until it's sorted.
 * WARNING: Highly inefficient for large arrays.
 */
object BogoSort {
    private val random = Random()

    fun sort(arr: IntArray): IntArray {
        if (arr.size <= 1) {
            return arr.copyOf()
        }

        val result = arr.copyOf()
        while (!isSorted(result)) {
            shuffle(result)
        }
        return result
    }

    private fun isSorted(arr: IntArray): Boolean {
        for (i in 0 until arr.size - 1) {
            if (arr[i] > arr[i + 1]) {
                return false
            }
        }
        return true
    }

    private fun shuffle(arr: IntArray) {
        for (i in arr.size - 1 downTo 1) {
            val j = random.nextInt(i + 1)
            val temp = arr[i]
            arr[i] = arr[j]
            arr[j] = temp
        }
    }
}

use rand::seq::SliceRandom;
use rand::thread_rng;

/**
 * Bogo Sort implementation.
 * Repeatedly shuffles the array until it's sorted.
 * WARNING: Highly inefficient for large arrays.
 */
pub fn bogo_sort(arr: &[i32]) -> Vec<i32> {
    if arr.len() <= 1 {
        return arr.to_vec();
    }

    let mut result = arr.to_vec();
    let mut rng = thread_rng();

    while !is_sorted(&result) {
        result.shuffle(&mut rng);
    }

    result
}

fn is_sorted(arr: &[i32]) -> bool {
    for i in 0..arr.len().saturating_sub(1) {
        if arr[i] > arr[i + 1] {
            return false;
        }
    }
    true
}

package algorithms.sorting.bogo

import scala.util.Random

/**
 * Bogo Sort implementation.
 * Repeatedly shuffles the array until it's sorted.
 * WARNING: Highly inefficient for large arrays.
 */
object BogoSort {
  private val random = new Random()

  def sort(arr: Array[Int]): Array[Int] = {
    if (arr.length <= 1) {
      return arr.clone()
    }

    val result = arr.clone()
    while (!isSorted(result)) {
      shuffle(result)
    }
    result
  }

  private def isSorted(arr: Array[Int]): Boolean = {
    for (i <- 0 until arr.length - 1) {
      if (arr[i] > arr[i + 1]) {
        return false
      }
    }
    true
  }

  private def shuffle(arr: Array[Int]): Unit = {
    for (i <- arr.length - 1 to 1 by -1) {
      val j = random.nextInt(i + 1)
      val temp = arr[i]
      arr[i] = arr[j]
      arr[j] = temp
    }
  }
}

/**
